.sig-organic-hero {
  position: relative;
  width: min(100%, 980px);
  min-height: 440px;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(260px, 0.82fr);
  gap: 34px;
  align-items: stretch;
  padding: 42px;
  overflow: hidden;
  border: 1px solid rgba(79,123,88,0.22);
  border-radius: 30px;
  background: linear-gradient(145deg, #f5f3e7, #dfe7d3);
  color: #233128;
  box-shadow: 0 30px 70px rgba(68,92,68,0.18);
  font-family: Inter, ui-sans-serif, system-ui, sans-serif;
}
.sig-organic-hero::before { content: ""; position: absolute; inset: 0; background: radial-gradient(circle at 15% 20%, rgba(79,123,88,0.18), transparent 24%), radial-gradient(circle at 80% 74%, rgba(176,131,69,0.16), transparent 26%); background-size: auto; opacity: 0.78; pointer-events: none; }
.sig-organic-hero > * { position: relative; z-index: 1; }
.sig-organic-hero .copy { display: grid; align-content: center; gap: 18px; }
.sig-organic-hero .kicker { width: fit-content; border: 1px solid rgba(79,123,88,0.22); border-radius: 999px; padding: 6px 10px; color: #4f7b58; background: #dfe7d3; font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-organic-hero h1 { margin: 0; max-width: 620px; font-family: Georgia, Times New Roman, serif; font-size: clamp(40px, 6.4vw, 70px); font-weight: 760; line-height: 0.98; letter-spacing: 0; }
.sig-organic-hero p { margin: 0; max-width: 560px; color: #60705f; font-size: 15px; line-height: 1.78; }
.sig-organic-hero .actions { display: flex; flex-wrap: wrap; gap: 10px; padding-top: 6px; }
.sig-organic-hero button { height: 40px; padding: 0 16px; border-radius: calc(30px / 2 + 4px); border: 1px solid rgba(79,123,88,0.22); font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; transition: transform 180ms cubic-bezier(0.16, 1, 0.3, 1), border-color 180ms; }
.sig-organic-hero .primary { background: #4f7b58; color: #f5f3e7; border-color: #4f7b58; }
.sig-organic-hero .secondary { background: transparent; color: #233128; }
.sig-organic-hero button:hover { transform: translateY(-1px); border-color: #4f7b58; }
.sig-organic-hero .artifact { display: grid; align-content: space-between; gap: 18px; padding: 22px; border: 1px solid rgba(79,123,88,0.22); border-radius: calc(30px - 2px); background: #dfe7d3; backdrop-filter: blur(18px) saturate(140%); }
.sig-organic-hero .artifact h2 { margin: 0; font-size: 13px; color: #4f7b58; text-transform: uppercase; letter-spacing: 0; }
.sig-organic-hero .metric-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.sig-organic-hero .metric { padding: 14px; border: 1px solid rgba(79,123,88,0.22); border-radius: calc(30px - 4px); background: color-mix(in srgb, #f5f3e7 76%, transparent); }
.sig-organic-hero .metric strong { display: block; font-size: 30px; line-height: 1; font-variant-numeric: tabular-nums; }
.sig-organic-hero .metric span { display: block; margin-top: 6px; color: #60705f; font-size: 11px; }
.sig-organic-hero .rail { height: 9px; border-radius: 999px; background: linear-gradient(90deg, #4f7b58, #b08345); }
@media (max-width: 780px) { .sig-organic-hero { grid-template-columns: 1fr; padding: 28px; } }

.sig-organic-card { width: min(100%, 390px); padding: 22px; border: 1px solid rgba(79,123,88,0.22); border-radius: 30px; background: #f5f3e7; color: #233128; box-shadow: 0 30px 70px rgba(68,92,68,0.18); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-organic-card .top { display: flex; align-items: start; justify-content: space-between; gap: 16px; margin-bottom: 24px; }
.sig-organic-card .label { color: #4f7b58; font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-organic-card .pill { border: 1px solid rgba(79,123,88,0.22); border-radius: 999px; padding: 5px 9px; color: #60705f; background: #dfe7d3; font-size: 11px; }
.sig-organic-card h3 { margin: 0 0 10px; font-family: Georgia, Times New Roman, serif; font-size: 32px; line-height: 1; letter-spacing: 0; }
.sig-organic-card p { margin: 0; color: #60705f; font-size: 13px; line-height: 1.7; }
.sig-organic-card .strip { display: grid; grid-template-columns: 1fr auto; gap: 12px; margin-top: 22px; padding-top: 16px; border-top: 1px solid rgba(79,123,88,0.22); }
.sig-organic-card .strip strong { font-variant-numeric: tabular-nums; color: #233128; }
.sig-organic-card .signal { width: 38px; height: 38px; display: grid; place-items: center; border-radius: calc(30px - 4px); background: #4f7b58; color: #f5f3e7; font-weight: 900; }

.sig-organic-nav { width: min(100%, 900px); min-height: 74px; display: flex; align-items: center; justify-content: space-between; gap: 24px; padding: 14px 16px; border: 1px solid rgba(79,123,88,0.22); border-radius: 30px; background: #f5f3e7; color: #233128; box-shadow: 0 30px 70px rgba(68,92,68,0.18); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-organic-nav .brand { display: flex; align-items: center; gap: 10px; min-width: max-content; font-family: Georgia, Times New Roman, serif; font-size: 15px; font-weight: 800; letter-spacing: 0; }
.sig-organic-nav .mark { width: 30px; height: 30px; border-radius: calc(30px - 4px); background: linear-gradient(135deg, #4f7b58, #b08345); box-shadow: inset 0 0 0 1px rgba(79,123,88,0.22); }
.sig-organic-nav .links { display: flex; align-items: center; gap: 4px; min-width: 0; overflow-x: auto; }
.sig-organic-nav a { height: 34px; display: inline-flex; align-items: center; padding: 0 12px; border-radius: calc(30px - 6px); color: #60705f; text-decoration: none; font-size: 13px; transition: color 160ms, background 160ms; white-space: nowrap; }
.sig-organic-nav a:hover, .sig-organic-nav a.active { color: #233128; background: #dfe7d3; }
.sig-organic-nav button { height: 34px; padding: 0 13px; border-radius: calc(30px - 6px); border: 1px solid #4f7b58; background: #4f7b58; color: #f5f3e7; font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; white-space: nowrap; }
@media (max-width: 720px) { .sig-organic-nav { align-items: stretch; flex-direction: column; } }

.sig-organic-form { width: min(100%, 440px); display: grid; gap: 15px; padding: 22px; border: 1px solid rgba(79,123,88,0.22); border-radius: 30px; background: #f5f3e7; color: #233128; box-shadow: 0 30px 70px rgba(68,92,68,0.18); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-organic-form label { display: grid; gap: 7px; font-size: 13px; font-weight: 800; color: #233128; }
.sig-organic-form small { color: #60705f; font-size: 12px; line-height: 1.55; font-weight: 400; }
.sig-organic-form .row { display: flex; gap: 10px; }
.sig-organic-form input { min-width: 0; flex: 1; height: 42px; border-radius: calc(30px - 6px); border: 1px solid rgba(79,123,88,0.22); background: #dfe7d3; color: #233128; padding: 0 12px; font: inherit; outline: none; transition: border-color 160ms, box-shadow 160ms; }
.sig-organic-form input:focus { border-color: #4f7b58; box-shadow: 0 0 0 3px color-mix(in srgb, #4f7b58 18%, transparent); }
.sig-organic-form button { height: 42px; padding: 0 14px; border-radius: calc(30px - 6px); border: 1px solid #4f7b58; background: #4f7b58; color: #f5f3e7; font: inherit; font-size: 13px; font-weight: 800; cursor: pointer; }
@media (max-width: 520px) { .sig-organic-form .row { flex-direction: column; } }

.sig-organic-table { width: min(100%, 780px); overflow: hidden; border: 1px solid rgba(79,123,88,0.22); border-radius: 30px; background: #f5f3e7; color: #233128; box-shadow: 0 30px 70px rgba(68,92,68,0.18); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-organic-table table { width: 100%; border-collapse: collapse; font-size: 13px; }
.sig-organic-table th, .sig-organic-table td { padding: 12px 14px; text-align: left; border-bottom: 1px solid rgba(79,123,88,0.22); }
.sig-organic-table th { color: #60705f; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0; background: #dfe7d3; }
.sig-organic-table td { color: #233128; }
.sig-organic-table tr:last-child td { border-bottom: 0; }
.sig-organic-table tbody tr:hover td { background: #dfe7d3; }
.sig-organic-table .mono { font-variant-numeric: tabular-nums; }
.sig-organic-table .status { display: inline-flex; align-items: center; gap: 6px; color: #4f7b58; font-weight: 800; }
.sig-organic-table .status::before { content: ""; width: 7px; height: 7px; border-radius: 50%; background: #4f7b58; }

.bg-aurora-real {
  min-height: 100vh;
  background: #020617;
  position: relative;
  overflow: hidden;
}
.bg-aurora-real .curtain {
  position: absolute;
  width: 200vw;
  height: 30vh;
  left: -50vw;
  border-radius: 50%;
  filter: blur(60px);
  animation: aurora-drift 40s ease-in-out infinite alternate;
}
.bg-aurora-real .c1 {
  top: 10%;
  background: rgba(34, 197, 94, 0.1);
  animation-delay: 0s;
}
.bg-aurora-real .c2 {
  top: 20%;
  background: rgba(6, 182, 212, 0.07);
  animation-delay: -12s;
}
.bg-aurora-real .c3 {
  top: 5%;
  background: rgba(34, 197, 94, 0.05);
  animation-delay: -24s;
  height: 20vh;
}
@keyframes aurora-drift {
  0% { transform: translateX(0) scaleY(1) rotate(0deg); }
  50% { transform: translateX(-5%) scaleY(1.3) rotate(1deg); }
  100% { transform: translateX(3%) scaleY(0.8) rotate(-1deg); }
}

.bg-paper-warm {
  min-height: 100vh;
  background: #faf9f7;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='p'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='1.2' numOctaves='3'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23p)' opacity='0.018'/%3E%3C/svg%3E");
}

.btn-soft-bounce {
  padding: 11px 22px;
  background: #ede9fe;
  color: #5b21b6;
  font-family: 'Inter', system-ui, sans-serif;
  font-size: 14px;
  font-weight: 600;
  border: none;
  border-radius: 12px;
  cursor: pointer;
  transition: all 0.35s cubic-bezier(0.34, 1.56, 0.64, 1);
  box-shadow: 0 0 0 rgba(91, 33, 182, 0);
}
.btn-soft-bounce:hover {
  transform: translateY(-3px);
  box-shadow: 0 8px 20px rgba(91, 33, 182, 0.12);
  background: #e0d7fa;
}
.btn-soft-bounce:active {
  transform: translateY(1px);
  box-shadow: 0 0 0 rgba(91, 33, 182, 0);
  background: #ddd6fe;
}

.btn-blob {
  padding: 13px 28px;
  background: #dcfce7;
  color: #166534;
  font-family: 'Inter', system-ui;
  font-size: 14px;
  font-weight: 500;
  border: none;
  border-radius: 60% 40% 70% 30% / 40% 60% 30% 70%;
  cursor: pointer;
  transition: all 0.3s;
  animation: blob-idle 6s ease-in-out infinite;
}
.btn-blob:hover {
  background: #bbf7d0;
  transform: scale(1.05);
  animation-play-state: paused;
}
@keyframes blob-idle {
  0%, 100% { border-radius: 60% 40% 70% 30% / 40% 60% 30% 70%; }
  33% { border-radius: 40% 60% 30% 70% / 60% 40% 70% 30%; }
  66% { border-radius: 70% 30% 50% 50% / 30% 70% 50% 50%; }
}

.card-nature {
  width: 300px;
  padding: 32px 28px;
  background: #fef9f0;
  border-radius: 28px;
  box-shadow: 0 4px 20px rgba(120,80,40,0.06);
}
.card-nature .emoji { font-size: 32px; margin-bottom: 16px; }
.card-nature h3 {
  font-family: 'Georgia', serif;
  font-size: 20px;
  font-weight: 700;
  color: #3d2c1e;
  margin: 0 0 10px;
}
.card-nature p {
  font-family: 'Inter', system-ui;
  font-size: 14px;
  color: #78716c;
  line-height: 1.7;
  margin: 0;
}
